import React, { useEffect, useState } from 'react';
import api from '../api/client';

const initialForm = {
  name: '',
  weight: '',
  criterion_type: '',
  description: ''
};

const CriteriaPage = () => {
  const [criteria, setCriteria] = useState([]);
  const [form, setForm] = useState(initialForm);
  const [editingId, setEditingId] = useState(null);

  const load = async () => {
    const { data } = await api.get('/criteria');
    setCriteria(data);
  };

  useEffect(() => {
    load();
  }, []);

  const submit = async (event) => {
    event.preventDefault();
    const payload = {
      ...form,
      weight: Number(form.weight)
    };

    if (editingId) {
      await api.put(`/criteria/${editingId}`, payload);
    } else {
      await api.post('/criteria', payload);
    }

    setForm(initialForm);
    setEditingId(null);
    await load();
  };

  const edit = (item) => {
    setEditingId(item.id);
    setForm({
      name: item.name,
      weight: item.weight,
      criterion_type: item.criterion_type || '',
      description: item.description || ''
    });
  };

  const remove = async (id) => {
    await api.delete(`/criteria/${id}`);
    await load();
  };

  return (
    <section>
      <h2>Критерии</h2>
      <form className="form" onSubmit={submit}>
        <input
          placeholder="Название критерия"
          value={form.name}
          onChange={(e) => setForm({ ...form, name: e.target.value })}
          required
        />
        <input
          type="number"
          min="0"
          step="0.1"
          placeholder="Вес"
          value={form.weight}
          onChange={(e) => setForm({ ...form, weight: e.target.value })}
          required
        />
        <input
          placeholder="Тип критерия"
          value={form.criterion_type}
          onChange={(e) => setForm({ ...form, criterion_type: e.target.value })}
        />
        <input
          placeholder="Описание"
          value={form.description}
          onChange={(e) => setForm({ ...form, description: e.target.value })}
        />
        <button type="submit">{editingId ? 'Сохранить изменения' : 'Добавить критерий'}</button>
      </form>

      <div className="table-wrapper">
        <table>
          <thead>
            <tr>
              <th>Критерий</th>
              <th>Вес</th>
              <th>Тип</th>
              <th>Описание</th>
              <th>Действия</th>
            </tr>
          </thead>
          <tbody>
            {criteria.map((item) => (
              <tr key={item.id}>
                <td>{item.name}</td>
                <td>{item.weight}</td>
                <td>{item.criterion_type}</td>
                <td>{item.description}</td>
                <td className="actions">
                  <button onClick={() => edit(item)}>Изменить</button>
                  <button className="danger" onClick={() => remove(item.id)}>
                    Удалить
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </section>
  );
};

export default CriteriaPage;
